export enum MessageType {
  TEXT = 'TEXT',
  FILE = 'FILE',
  SYSTEM = 'SYSTEM'
}

export interface ChatMessage {
  id: string;
  senderId: string;
  senderName: string;
  content: string; // Text content or File metadata (name, type, size)
  fileData?: string; // Base64 data for files
  type: MessageType;
  timestamp: number;
}

export interface UserProfile {
  id: string;
  name: string;
  avatarUrl: string;
}

export interface PeerState {
  myId: string;
  connectedPeerId: string | null;
  isConnectionOpen: boolean;
  connectionError: string | null;
}

import { GoogleGenAI } from "@google/genai";
import { ChatMessage, MessageType } from '../types';

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API_KEY is missing. AI features will not work.");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const generateSmartReply = async (messages: ChatMessage[]): Promise<string> => {
  const ai = getAiClient();
  if (!ai) return "AI unavailable";

  // Filter last 10 text messages for context
  const context = messages
    .filter(m => m.type === MessageType.TEXT)
    .slice(-10)
    .map(m => `${m.senderName}: ${m.content}`)
    .join('\n');

  const prompt = `You are a helpful communication assistant. Based on the following chat history, suggest 3 short, relevant, and polite reply options for the current user. Format them as a simple list separated by pipes (|). Do not add numbering or extra text.

  Chat History:
  ${context}

  Suggestions:`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });
    return response.text || "";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "";
  }
};

export const summarizeConversation = async (messages: ChatMessage[]): Promise<string> => {
  const ai = getAiClient();
  if (!ai) return "AI unavailable";

  const context = messages
    .filter(m => m.type === MessageType.TEXT)
    .map(m => `${m.senderName}: ${m.content}`)
    .join('\n');

  if (!context) return "No conversation to summarize.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Summarize the following conversation in a concise paragraph:\n\n${context}`,
    });
    return response.text || "Could not generate summary.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error generating summary.";
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
  icon?: React.ReactNode;
}

const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  icon,
  className = '', 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center px-4 py-2 rounded-lg font-medium transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-blue-600 hover:bg-blue-700 text-white shadow-lg shadow-blue-500/30 focus:ring-blue-500 border border-transparent",
    secondary: "bg-slate-700 hover:bg-slate-600 text-white border border-slate-600 focus:ring-slate-500",
    danger: "bg-red-600 hover:bg-red-700 text-white shadow-lg shadow-red-500/30 focus:ring-red-500 border border-transparent",
    ghost: "bg-transparent hover:bg-slate-800 text-slate-300 hover:text-white border border-transparent"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      ) : icon ? (
        <span className="mr-2">{icon}</span>
      ) : null}
      {children}
    </button>
  );
};

export default Button;

