             <p className="text-xs text-slate-400 flex items-center gap-1"><Shield className="w-3 h-3"/> Encrypted Connection</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 bg-slate-900 px-3 py-1.5 rounded-full border border-slate-700">
