          </div>
          <Button variant="ghost" onClick={() => window.location.reload()}>
            <LogOut className="w-5 h-5 text-slate-400 hover:text-red-400 transition-colors" />
          </Button>
        </div>
      </nav>

      <main className="flex-1 p-4 md:p-6 container mx-auto max-w-7xl flex flex-col md:flex-row gap-6">

        {/* Sidebar / Connection Panel */}
        <aside className="w-full md:w-80 flex flex-col gap-6">
           {/* My Status Card */}
           <div className="bg-slate-800 rounded-xl p-5 border border-slate-700 shadow-lg relative overflow-hidden">
              <div className="absolute top-0 left-0 w-1 h-full bg-blue-500"></div>
              <h2 className="text-sm uppercase tracking-wider text-slate-400 font-semibold mb-3">My Connection ID</h2>
              <div className="flex gap-2">
                <code className="flex-1 bg-slate-900 p-3 rounded-lg text-sm font-mono truncate border border-slate-700 text-blue-300">
                  {peerState.myId || 'Generating ID...'}
                </code>
                <Button onClick={copyId} variant="secondary" className="px-3">
                  {copied ? <Check className="w-4 h-4 text-green-400"/> : <Copy className="w-4 h-4"/>}
                </Button>
              </div>
              <p className="text-xs text-slate-500 mt-2">Share this ID with a friend to connect.</p>
