           {/* Connect to Peer Card */}
           <div className="bg-slate-800 rounded-xl p-5 border border-slate-700 shadow-lg">
              <h2 className="text-sm uppercase tracking-wider text-slate-400 font-semibold mb-3">Connect to Peer</h2>
              {!peerState.isConnectionOpen ? (
                <div className="flex flex-col gap-3">
                  <input
                    type="text"
                    placeholder="Enter Peer ID"
                    value={targetPeerId}
                    onChange={(e) => setTargetPeerId(e.target.value)}
                    className="w-full bg-slate-900 border border-slate-600 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 outline-none transition-all placeholder-slate-600"
                  />
                  <Button 
