                  <div className="w-2 h-2 bg-green-500 rounded-full mx-auto mb-2 shadow-[0_0_10px_rgba(34,197,94,0.5)]"></div>
                  <p className="text-green-400 font-medium text-sm">Connected to Peer</p>
                  <p className="text-xs text-green-300/50 font-mono mt-1">{peerState.connectedPeerId}</p>
                </div>
