                Use Gemini to summarize your chats or suggest quick replies during intense gaming or coding sessions.
              </p>
           </div>
        </aside>

        {/* Main Content Area */}
        <div className="flex-1 grid grid-rows-[1fr_1fr] md:grid-rows-1 md:grid-cols-2 gap-6 h-[80vh]">

          {/* Chat Section */}
          <section className="h-full min-h-[300px]">
            <ChatInterface 
              connection={dataConnection} 
              currentUser={user}
              messages={messages}
              onSendMessage={handleSendMessage}
            />
          </section>

          {/* Video Section */}
          <section className="h-full min-h-[300px]">
             {peerInstance ? (
               <VideoInterface 
                  peer={peerInstance}
                  remotePeerId={peerState.connectedPeerId}
                  incomingCall={incomingCall}
                  onCallEnd={() => setIncomingCall(null)}
               />
             ) : (
               <div className="h-full flex items-center justify-center bg-slate-800 rounded-xl border border-slate-700">
                  <p className="text-slate-500">Initializing Video Service...</p>
               </div>
             )}
          </section>

        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import Peer, { MediaConnection } from 'peerjs';
import Button from './Button';
import { Mic, MicOff, Video as VideoIcon, VideoOff, PhoneOff, Monitor, MonitorOff, PhoneIncoming, Phone } from 'lucide-react';

interface VideoInterfaceProps {
  peer: Peer;
  remotePeerId: string | null;
  incomingCall: MediaConnection | null;
  onCallEnd: () => void;
}

const VideoInterface: React.FC<VideoInterfaceProps> = ({ peer, remotePeerId, incomingCall, onCallEnd }) => {
  const [localStream, setLocalStream] = useState<MediaStream | null>(null);
  const [remoteStream, setRemoteStream] = useState<MediaStream | null>(null);
  const [activeCall, setActiveCall] = useState<MediaConnection | null>(null);

  const [isMuted, setIsMuted] = useState(false);
  const [isVideoOff, setIsVideoOff] = useState(false);
  const [isScreenSharing, setIsScreenSharing] = useState(false);

  const localVideoRef = useRef<HTMLVideoElement>(null);
  const remoteVideoRef = useRef<HTMLVideoElement>(null);

  // Handle local video element
  useEffect(() => {
    if (localVideoRef.current && localStream) {
      localVideoRef.current.srcObject = localStream;
    }
  }, [localStream]);

  // Handle remote video element
  useEffect(() => {
    if (remoteVideoRef.current && remoteStream) {
      remoteVideoRef.current.srcObject = remoteStream;
    }
  }, [remoteStream]);

  // Clean up if incoming call is cancelled by caller before we answer
  useEffect(() => {
    if (!incomingCall && !activeCall) {
       // Reset if call cancelled
    }
    if (incomingCall) {
        incomingCall.on('close', () => {
            endCall();
        });
    }
  }, [incomingCall, activeCall]);

  const answerCall = () => {
    if (!incomingCall) return;

    navigator.mediaDevices.getUserMedia({ video: true, audio: true })
      .then((stream) => {
        setLocalStream(stream);
        incomingCall.answer(stream);
        setActiveCall(incomingCall);

        incomingCall.on('stream', (remoteStream) => {
          setRemoteStream(remoteStream);
        });
      })
      .catch(err => {
          console.error("Failed to get local stream", err);
          endCall();
      });
  };

  const rejectCall = () => {
      incomingCall?.close();
      onCallEnd();
  };

  const startCall = () => {
    if (!remotePeerId) return;
    navigator.mediaDevices.getUserMedia({ video: true, audio: true })
      .then((stream) => {
        setLocalStream(stream);
        const newCall = peer.call(remotePeerId, stream);
        setActiveCall(newCall);

        newCall.on('stream', (remoteStream) => {
          setRemoteStream(remoteStream);
        });

        newCall.on('close', () => endCall());
      })
      .catch(err => console.error("Failed to get local stream", err));
  };

  const endCall = () => {
    activeCall?.close();
    localStream?.getTracks().forEach(track => track.stop());
    setLocalStream(null);
    setRemoteStream(null);
    setActiveCall(null);
    setIsScreenSharing(false);
    onCallEnd();
  };

  const toggleMute = () => {
    if (localStream) {
      localStream.getAudioTracks().forEach(track => track.enabled = !track.enabled);
      setIsMuted(!isMuted);
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      localStream.getVideoTracks().forEach(track => track.enabled = !track.enabled);
      setIsVideoOff(!isVideoOff);
    }
  };

  const toggleScreenShare = async () => {
    if (!activeCall || !localStream) return;

    if (isScreenSharing) {
      // Stop screen share, revert to camera
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
        const videoTrack = stream.getVideoTracks()[0];

        const sender = activeCall.peerConnection.getSenders().find(s => s.track?.kind === 'video');
        if (sender) {
            await sender.replaceTrack(videoTrack);
        }

        setLocalStream((prev) => {
            if(!prev) return stream;
            // Stop old tracks (screen share)
            prev.getVideoTracks().forEach(t => t.stop());
            return new MediaStream([videoTrack, ...prev.getAudioTracks()]);
        });
        setIsScreenSharing(false);
        setIsVideoOff(false); 
      } catch (err) {
        console.error("Error reverting to camera", err);
      }
    } else {
      // Start screen share
      try {
        const stream = await navigator.mediaDevices.getDisplayMedia({ video: true });
        const screenTrack = stream.getVideoTracks()[0];

        const sender = activeCall.peerConnection.getSenders().find(s => s.track?.kind === 'video');
        if (sender) {
            await sender.replaceTrack(screenTrack);
        }

        screenTrack.onended = () => {
            toggleScreenShare(); 
        };

        setLocalStream((prev) => {
            if (!prev) return stream;
            return new MediaStream([screenTrack, ...prev.getAudioTracks()]);
        });
        setIsScreenSharing(true);
      } catch (err) {
        console.error("Error starting screen share", err);
      }
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 rounded-xl overflow-hidden shadow-2xl border border-slate-700 relative">
      <div className="relative flex-1 bg-black">
        {/* Remote Video */}
        {remoteStream ? (
          <video 
            ref={remoteVideoRef} 
            autoPlay 
            playsInline
            className="w-full h-full object-cover" 
          />
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center text-slate-500 bg-slate-900">
             {incomingCall && !activeCall ? (
                 <div className="text-center animate-pulse">
                     <div className="w-20 h-20 bg-blue-600 rounded-full flex items-center justify-center mx-auto mb-4 shadow-[0_0_20px_rgba(37,99,235,0.5)]">
                        <PhoneIncoming className="w-10 h-10 text-white" />
                     </div>
                     <h3 className="text-xl font-semibold text-white">Incoming Call...</h3>
                     <p className="text-sm text-slate-400 mt-2">{incomingCall.peer}</p>
                 </div>
             ) : activeCall ? (
                 <p>Connecting...</p>
             ) : (
                 <div className="flex flex-col items-center">
                    <VideoIcon className="w-12 h-12 mb-2 opacity-20"/>
                    <p>Ready to call</p>
                 </div>
             )}
          </div>
        )}

        {/* Local Video (PiP) */}
        {activeCall && (
            <div className="absolute bottom-4 right-4 w-32 h-48 md:w-48 md:h-36 bg-slate-800 rounded-lg overflow-hidden border-2 border-slate-600 shadow-lg transition-all hover:scale-105">
            {localStream ? (
                <video 
                ref={localVideoRef} 
                autoPlay 
                playsInline 
                muted 
                className={`w-full h-full object-cover ${isVideoOff ? 'hidden' : ''}`} 
                />
            ) : <div className="w-full h-full bg-slate-800 flex items-center justify-center"><VideoIcon className="w-6 h-6 text-slate-500"/></div>}
            {isVideoOff && <div className="absolute inset-0 flex items-center justify-center bg-slate-800 text-slate-500"><VideoOff className="w-8 h-8"/></div>}
            </div>
        )}
      </div>

      {/* Controls */}
      <div className="h-20 bg-slate-800 flex items-center justify-center gap-4 px-4 border-t border-slate-700">

        {/* Case 1: Incoming Call (Ringing) */}
        {incomingCall && !activeCall && (
            <>
                <Button onClick={answerCall} variant="primary" className="bg-green-600 hover:bg-green-700 rounded-full px-6">
                    <Phone className="w-5 h-5 mr-2" /> Answer
                </Button>
                <Button onClick={rejectCall} variant="danger" className="rounded-full px-6">
                    <PhoneOff className="w-5 h-5 mr-2" /> Decline
                </Button>
            </>
        )}

        {/* Case 2: No Active Call & No Incoming */}
        {!activeCall && !incomingCall && (
          <Button onClick={startCall} variant="primary" className="rounded-full w-12 h-12 p-0 flex items-center justify-center bg-green-600 hover:bg-green-700" disabled={!remotePeerId}>
            <VideoIcon className="w-6 h-6" />
          </Button>
        )}

        {/* Case 3: Active Call */}
        {activeCall && (
          <>
            <Button onClick={toggleMute} variant={isMuted ? 'danger' : 'secondary'} className="rounded-full w-12 h-12 p-0 flex items-center justify-center">
              {isMuted ? <MicOff className="w-5 h-5" /> : <Mic className="w-5 h-5" />}
            </Button>

            <Button onClick={toggleVideo} variant={isVideoOff ? 'danger' : 'secondary'} className="rounded-full w-12 h-12 p-0 flex items-center justify-center">
              {isVideoOff ? <VideoOff className="w-5 h-5" /> : <VideoIcon className="w-5 h-5" />}
            </Button>

            <Button onClick={toggleScreenShare} variant={isScreenSharing ? 'primary' : 'secondary'} className="rounded-full w-12 h-12 p-0 flex items-center justify-center">
               {isScreenSharing ? <MonitorOff className="w-5 h-5" /> : <Monitor className="w-5 h-5" />}
            </Button>

            <Button onClick={endCall} variant="danger" className="rounded-full w-14 h-14 p-0 flex items-center justify-center shadow-red-500/50">
              <PhoneOff className="w-6 h-6" />
            </Button>
          </>
        )}
      </div>
    </div>
  );
};

export default VideoInterface;

import React, { useState, useRef, useEffect } from 'react';
import { DataConnection } from 'peerjs';
import { ChatMessage, MessageType, UserProfile } from '../types';
import Button from './Button';
import { Send, Paperclip, FileText, Download, Sparkles, Bot } from 'lucide-react';
import * as geminiService from '../services/geminiService';

interface ChatInterfaceProps {
  connection: DataConnection | null;
  currentUser: UserProfile;
  messages: ChatMessage[];
  onSendMessage: (msg: ChatMessage) => void;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ connection, currentUser, messages, onSendMessage }) => {
  const [inputText, setInputText] = useState('');
  const [isAiThinking, setIsAiThinking] = useState(false);
  const [suggestedReplies, setSuggestedReplies] = useState<string[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendText = (text: string = inputText) => {
    if (!text.trim() || !connection) return;

    const msg: ChatMessage = {
      id: crypto.randomUUID(),
      senderId: currentUser.id,
      senderName: currentUser.name,
      content: text,
      type: MessageType.TEXT,
      timestamp: Date.now()
    };

    connection.send(msg);
    onSendMessage(msg);
    setInputText('');
    setSuggestedReplies([]); // Clear suggestions after sending
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !connection) return;

    // Safety check for WebRTC data channel limits (simplistic implementation)
    // 500KB limit to be safe for Chrome without chunking logic
    if (file.size > 500 * 1024) {
        alert("File too large. For this demo, please select files under 500KB.");
        if (fileInputRef.current) fileInputRef.current.value = '';
        return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64Data = event.target?.result as string;
      const msg: ChatMessage = {
        id: crypto.randomUUID(),
        senderId: currentUser.id,
        senderName: currentUser.name,
        content: file.name, // Display name
        fileData: base64Data,
        type: MessageType.FILE,
        timestamp: Date.now()
      };

      connection.send(msg);
      onSendMessage(msg);
    };
    reader.readAsDataURL(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const downloadFile = (dataUrl: string, fileName: string) => {
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleAiSuggestions = async () => {
    setIsAiThinking(true);
    const suggestionsRaw = await geminiService.generateSmartReply(messages);
    if (suggestionsRaw) {
        // Parse the pipe-separated list
        const list = suggestionsRaw.split('|').map(s => s.trim()).filter(s => s.length > 0);
        setSuggestedReplies(list);
    }
    setIsAiThinking(false);
  };

  const handleSummarize = async () => {
      setIsAiThinking(true);
      const summary = await geminiService.summarizeConversation(messages);

      // Add as a local system message just for this user
      const msg: ChatMessage = {
          id: crypto.randomUUID(),
          senderId: 'ai-bot',
          senderName: 'Gemini AI',
          content: summary,
          type: MessageType.SYSTEM,
          timestamp: Date.now()
      };
      onSendMessage(msg); // Only adds to local view effectively if we don't send it over wire
      setIsAiThinking(false);
  }

  return (
    <div className="flex flex-col h-full bg-slate-800 rounded-xl overflow-hidden shadow-xl border border-slate-700">
      {/* Header */}
      <div className="p-4 bg-slate-900 border-b border-slate-700 flex justify-between items-center">
        <h3 className="font-semibold text-white">Chat Room</h3>
        <div className="flex gap-2">
            <Button 
                variant="ghost" 
                className="text-xs py-1 px-2 h-auto text-purple-400 hover:text-purple-300 hover:bg-purple-900/20"
                onClick={handleSummarize}
                disabled={isAiThinking}
                title="Summarize with AI"
            >
                <Bot className="w-4 h-4 mr-1"/> Summarize
            </Button>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-800/50">
        {messages.map((msg) => {
          const isMe = msg.senderId === currentUser.id;
          const isSystem = msg.type === MessageType.SYSTEM;

          if (isSystem) {
              return (
                  <div key={msg.id} className="flex justify-center my-4">
                      <div className="bg-purple-900/30 border border-purple-500/30 text-purple-200 text-sm p-3 rounded-lg max-w-[80%] flex items-start">
                          <Sparkles className="w-4 h-4 mr-2 mt-0.5 flex-shrink-0" />
                          <div>
                            <p className="font-bold text-xs mb-1">AI Summary</p>
                            {msg.content}
                          </div>
                      </div>
                  </div>
              )
          }

          return (
            <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[70%] rounded-2xl p-3 ${
                isMe 
                  ? 'bg-blue-600 text-white rounded-br-none' 
                  : 'bg-slate-700 text-slate-200 rounded-bl-none'
              }`}>
                {!isMe && <p className="text-xs text-slate-400 mb-1">{msg.senderName}</p>}

                {msg.type === MessageType.TEXT && <p className="whitespace-pre-wrap">{msg.content}</p>}

                {msg.type === MessageType.FILE && (
                  <div className="flex items-center gap-3 p-2 bg-black/20 rounded-lg">
                    <FileText className="w-8 h-8 opacity-70" />
                    <div className="overflow-hidden">
                      <p className="font-medium text-sm truncate">{msg.content}</p>
                      <p className="text-xs opacity-70">File</p>
                    </div>
                    {msg.fileData && (
                      <button 
                        onClick={() => downloadFile(msg.fileData!, msg.content)}
                        className="p-1.5 hover:bg-white/10 rounded-full transition-colors"
                        title="Download"
                      >
                        <Download className="w-4 h-4" />
                      </button>
                    )}
                  </div>
                )}

                <p className="text-[10px] opacity-50 text-right mt-1">
                  {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                </p>
              </div>
            </div>
          );
        })}
        <div ref={messagesEndRef} />
      </div>

      {/* Suggested Replies */}
      {suggestedReplies.length > 0 && (
          <div className="px-4 py-2 bg-slate-700/50 flex gap-2 overflow-x-auto">
              {suggestedReplies.map((reply, idx) => (
                  <button 
                    key={idx}
                    onClick={() => handleSendText(reply)}
                    className="flex-shrink-0 text-xs bg-slate-600 hover:bg-blue-600 text-white px-3 py-1.5 rounded-full transition-colors border border-slate-500"
                  >
                      {reply}
                  </button>
              ))}
          </div>
      )}

      {/* Input Area */}
      <div className="p-4 bg-slate-900 border-t border-slate-700">
        <div className="flex items-center gap-2">
           <Button 
            variant="ghost" 
            className="p-2 h-10 w-10 rounded-full text-purple-400 hover:text-purple-300"
            onClick={handleAiSuggestions}
            disabled={isAiThinking}
            title="Get AI Suggestions"
           >
             <Sparkles className={`w-5 h-5 ${isAiThinking ? 'animate-pulse' : ''}`} />
           </Button>

          <button 
            onClick={() => fileInputRef.current?.click()}
            className="p-2 text-slate-400 hover:text-white transition-colors"
            title="Send File"
          >
            <Paperclip className="w-5 h-5" />
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            onChange={handleFileSelect}
          />

          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSendText()}
            placeholder="Type a message..."
            className="flex-1 bg-slate-800 border-none rounded-full px-4 py-2 focus:ring-2 focus:ring-blue-500 text-white placeholder-slate-500 outline-none"
            disabled={!connection}
          />

          <Button 
            onClick={() => handleSendText()} 
            disabled={!connection || !inputText.trim()}
            className="rounded-full w-10 h-10 p-0 flex items-center justify-center"
          >
            <Send className="w-4 h-4 ml-0.5" />
          </Button>
        </div>
      </div>
    </div>
  );
};

export default ChatInterface;

